<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Falling Sand Sandbox</title>
<style>
  :root { --bg: #1a1a1a; --panel: #252525; --text: #eee; }
  body { margin: 0; background: var(--bg); color: var(--text); font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif; display: flex; flex-direction: column; align-items: center; height: 100vh; overflow: hidden; user-select: none; }
  h1 { margin: 15px 0; font-size: 1.2rem; opacity: 0.9; letter-spacing: 1px; }

  #controls { display: flex; gap: 8px; margin-bottom: 15px; background: var(--panel); padding: 10px; border-radius: 8px; box-shadow: 0 4px 6px rgba(0,0,0,0.3); }
  button { padding: 8px 12px; border: none; border-radius: 4px; cursor: pointer; font-weight: bold; transition: all 0.2s ease; color: white; background: #444; font-size: 0.9rem; }
  button:hover { transform: translateY(-2px); filter: brightness(1.1); box-shadow: 0 2px 5px rgba(0,0,0,0.2); }
  button.active { outline: 2px solid white; box-shadow: 0 0 8px rgba(255,255,255,0.4); transform: translateY(-1px); }

  #mat-sand { background: #e6c87a; color: #332b00; }
  #mat-water { background: #4da6ff; color: #001f3f; }
  #mat-wall { background: #666; color: #333; border: 1px solid #555; }
  #mat-acid { background: #aaffaa; color: #004d00; }
  #mat-empty { background: #222; color: #888; border: 1px dashed #444; }

  #clear { background: #ff4444; color: white; font-size: 0.8rem; padding: 6px 10px; }
  #clear:hover { background: #ff2222; }

  canvas { 
    background: #000; 
    border-radius: 4px; 
    box-shadow: 0 0 30px rgba(0,0,0,0.6); 
    cursor: crosshair;
    image-rendering: pixelated; 
    max-width: 95vw;
    max-height: 70vh;
  }
</style>
</head>
<body>

<h1>Falling Sand Sandbox</h1>

<div id="controls">
  <button id="mat-sand" class="active">Sand</button>
  <button id="mat-water">Water</button>
  <button id="mat-wall">Wall</button>
  <button id="mat-acid">Acid</button>
  <button id="mat-empty">Eraser</button>
  <div style="width:1px; background:#444; margin:0 5px;"></div>
  <button id="clear">Clear All</button>
</div>

<canvas id="sand"></canvas>

<script>
(function() {
  // Configuration
  const W = 80;
  const H = 80;
  const SCALE = 5; 

  // Materials
  const MATS = ['empty', 'sand', 'water', 'wall', 'acid'];

  // State
  let grid = new Array(W * H).fill('empty');
  let selectedMat = 'sand';
  let isMouseDown = false;
  let mouseX = 0;
  let mouseY = 0;

  const canvas = document.getElementById('sand');
  const ctx = canvas.getContext('2d');

  // Setup Canvas Size
  canvas.width = W * SCALE;
  canvas.height = H * SCALE;

  // --- API Implementation ---

  window.sim = {
    w: W,
    h: H,

    tick: function(n) {
      for (let i = 0; i < n; i++) {
        update();
      }
    },

    get: function(x, y) {
      if (x < 0 || x >= W || y < 0 || y >= H) return 'wall'; // Boundaries act as walls
      return grid[y * W + x];
    },

    set: function(x, y, mat) {
      if (x < 0 || x >= W || y < 0 || y >= H) return;
      grid[y * W + x] = mat;
    },

    clear: function() {
      for(let i=0; i<grid.length; i++) grid[i] = 'empty';
    }
  };

  // --- Simulation Logic ---

  function update() {
    // Iterate bottom-up to prevent teleportation (particles settle before moving up)
    for (let y = H - 2; y >= 0; y--) {
      for (let x = 0; x < W; x++) {
        const idx = y * W + x;
        const cell = grid[idx];

        // Skip empty and walls
        if (cell === 'empty' || cell === 'wall') continue;

        let moved = false;

        // Acid Logic: Dissolve neighbors first? 
        // "Acid moves like water, and additionally dissolves sand or wall cells it touches below or beside"

        if (cell === 'acid') {
            const neighbors = [
                {dx: 0, dy: 1}, {dx: -1, dy: 0}, {dx: 1, dy: 0}
            ];
            for(let n of neighbors) {
                let nx = x + n.dx;
                let ny = y + n.dy;
                if (nx >= 0 && nx < W && ny >= 0 && ny < H) {
                    const targetIdx = ny * W + nx;
                    const target = grid[targetIdx];
                    if (target === 'sand' || target === 'wall') {
                        // Dissolve target
                        grid[targetIdx] = 'empty';
                    }
                }
            }
        }

        // Movement Logic
        // 1. Try Down (y+1)
        const downIdx = (y + 1) * W + x;
        const downCell = grid[downIdx];

        if (cell === 'sand' || cell === 'water' || cell === 'acid') {
            if (downCell === 'empty' || downCell === 'water' || downCell === 'acid') {
                // Swap or Move Down
                const temp = grid[idx];
                grid[idx] = downCell;
                grid[downIdx] = temp;
                moved = true;
            } else if (cell === 'sand') {
                // Sand blocked below: Slide Diagonally
                // Check Left-Down
                const leftDownIdx = (y + 1) * W + (x - 1);
                const rightDownIdx = (y + 1) * W + (x + 1);

                let moveX = 0;
                if (x > 0 && grid[leftDownIdx] === 'empty') {
                    moveX = -1;
                } else if (x < W - 1 && grid[rightDownIdx] === 'empty') {
                    moveX = 1;
                }

                if (moveX !== 0) {
                    const targetIdx = (y + 1) * W + (x + moveX);
                    const temp = grid[idx];
                    grid[idx] = grid[targetIdx];
                    grid[targetIdx] = temp;
                    moved = true;
                }
            } else if (cell === 'water' || cell === 'acid') {
                // Water/Acid blocked below: Spread Horizontally
                const leftIdx = y * W + (x - 1);
                const rightIdx = y * W + (x + 1);

                let moveX = 0;
                if (x > 0 && grid[leftIdx] === 'empty') {
                    moveX = -1;
                } else if (x < W - 1 && grid[rightIdx] === 'empty') {
                    moveX = 1;
                }

                if (moveX !== 0) {
                    const targetIdx = y * W + (x + moveX);
                    const temp = grid[idx];
                    grid[idx] = grid[targetIdx];
                    grid[targetIdx] = temp;
                    moved = true;
                }
            }
        }
      }
    }
  }

  // --- Rendering ---

  function draw() {
    ctx.fillStyle = '#000';
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    for (let y = 0; y < H; y++) {
      for (let x = 0; x < W; x++) {
        const mat = grid[y * W + x];
        if (!mat) continue; // empty is transparent or black

        const px = x * SCALE;
        const py = y * SCALE;

        ctx.fillStyle = getMaterialColor(mat);

        // Draw slightly smaller than cell for "pixel" look
        ctx.fillRect(px, py, SCALE - 1, SCALE - 1);
      }
    }

    // Highlight mouse cursor position if painting
    if (isMouseDown) {
        const mx = Math.floor(mouseX / SCALE) * SCALE;
        const my = Math.floor(mouseY / SCALE) * SCALE;
        ctx.strokeStyle = 'rgba(255, 255, 255, 0.3)';
        ctx.lineWidth = 1;
        ctx.strokeRect(mx, my, SCALE, SCALE);
    }
  }

  function getMaterialColor(mat) {
    switch(mat) {
      case 'sand': return '#e6c87a'; // Sand color
      case 'water': return '#4da6ff'; // Water color
      case 'wall': return '#555';     // Wall color
      case 'acid': return '#aaffaa';  // Acid color
      default: return '#000';         // Empty
    }
  }

  // --- Interaction ---

  function paint() {
    const gx = Math.floor(mouseX / SCALE);
    const gy = Math.floor(mouseY / SCALE);

    if (gx >= 0 && gx < W && gy >= 0 && gy < H) {
        window.sim.set(gx, gy, selectedMat);
    }
  }

  canvas.addEventListener('mousedown', e => {
    isMouseDown = true;
    updateMouse(e);
    paint();
  });

  canvas.addEventListener('mousemove', e => {
    if (isMouseDown) {
        updateMouse(e);
        paint();
    }
  });

  window.addEventListener('mouseup', () => {
    isMouseDown = false;
  });

  function updateMouse(e) {
    const rect = canvas.getBoundingClientRect();
    mouseX = e.clientX - rect.left;
    mouseY = e.clientY - rect.top;
  }

  // UI Wiring
  document.getElementById('mat-sand').onclick = () => selectMat('sand');
  document.getElementById('mat-water').onclick = () => selectMat('water');
  document.getElementById('mat-wall').onclick = () => selectMat('wall');
  document.getElementById('mat-acid').onclick = () => selectMat('acid');
  document.getElementById('mat-empty').onclick = () => selectMat('empty');

  function selectMat(mat) {
    selectedMat = mat;
    document.querySelectorAll('#controls button').forEach(b => b.classList.remove('active'));
    const btn = document.getElementById('mat-' + mat);
    if(btn) btn.classList.add('active');
  }

  document.getElementById('clear').onclick = () => {
      window.sim.clear();
      draw();
  };

  // Initial Draw
  draw();

})();
</script>
</body>
</html>
